module top_module (
  input in,
  input [2:0] state,
  output reg [2:0] next_state,
  output reg input_data
);

  // One-hot state encoding
  parameter D = 3'b001;
  parameter E = 3'b010;
  parameter F = 3'b100;

  always @(*) begin
    // Default values
    next_state = 3'b000;
    input_data = 0;

    case (state)
      D: begin
        if (in == 0)
          next_state = E;
        else
          next_state = F;
        input_data = 0;
      end

      E: begin
        if (in == 0)
          next_state = F;
        else
          next_state = D;
        input_data = 1;
      end

      F: begin
        if (in == 0)
          next_state = D;
        else
          next_state = E;
        input_data = 0;
      end

      default: begin
        next_state = D; // Default to state D in case of an undefined state
        input_data = 0;
      end
    endcase
  end

endmodule
